#!/usr/bin/env python3
"""
build_harvest_corpus.py

Builds a diverse text corpus for harvesting vocabulary from Qwen3.5-35B.
Sources:
  1. Protocol doc: docs/protocols/20260324-unified-consciousness-protocol-6.2.md
  2. Handcrafted general-knowledge texts covering broad vocabulary domains.

Output: scripts/harvest_corpus.json — a JSON list of strings.
"""

import json
import re
from pathlib import Path

REPO_ROOT = Path(__file__).parent.parent
PROTOCOL_PATH = REPO_ROOT / "docs/protocols/20260324-unified-consciousness-protocol-6.2.md"
OUTPUT_PATH = Path(__file__).parent / "harvest_corpus.json"

MIN_CHARS = 50
MAX_CHARS = 2000


# ---------------------------------------------------------------------------
# 1. Extract paragraphs from the protocol document
# ---------------------------------------------------------------------------


def extract_protocol_paragraphs(path: Path) -> list[str]:
    text = path.read_text(encoding="utf-8")

    # Split on blank lines; keep multi-sentence blocks
    raw_blocks = re.split(r"\n{2,}", text)

    paragraphs = []
    for block in raw_blocks:
        block = block.strip()
        # Skip pure code blocks, tables, and very short lines
        if block.startswith("```") or block.startswith("$$"):
            continue
        if block.startswith("|") and block.count("|") > 4:
            # Table — skip
            continue
        # Strip markdown headers, bold markers, inline code backticks
        clean = re.sub(r"^#+\s*", "", block, flags=re.MULTILINE)
        clean = re.sub(r"\*\*(.+?)\*\*", r"\1", clean)
        clean = re.sub(r"\*(.+?)\*", r"\1", clean)
        clean = re.sub(r"`(.+?)`", r"\1", clean)
        clean = re.sub(r"\$\$?.+?\$\$?", "", clean, flags=re.DOTALL)
        clean = re.sub(r"\[(.+?)\]\(.+?\)", r"\1", clean)  # links
        clean = re.sub(r"→|←|↓|↑|↕|✅|⚠️|🔬|🔧|📐|🟡", " ", clean)
        clean = re.sub(r"\s+", " ", clean).strip()

        if MIN_CHARS <= len(clean) <= MAX_CHARS:
            paragraphs.append(clean)

    return paragraphs


