# ---------------------------------------------------------------------------
# 3. Assemble and save
# ---------------------------------------------------------------------------


def main():
    # --- Protocol paragraphs ---
    protocol_paragraphs = extract_protocol_paragraphs(PROTOCOL_PATH)
    print(f"Protocol paragraphs extracted: {len(protocol_paragraphs)}")

    # --- General texts ---
    general_texts = [t.strip() for t in GENERAL_TEXTS if MIN_CHARS <= len(t.strip()) <= MAX_CHARS]
    print(f"General-knowledge texts: {len(general_texts)}")

    # --- Combine and deduplicate by first 80 chars ---
    seen = set()
    corpus = []
    for text in protocol_paragraphs + general_texts:
        key = text[:80]
        if key not in seen:
            seen.add(key)
            corpus.append(text)

    # --- Stats ---
    total_chars = sum(len(t) for t in corpus)
    # ~4 chars per token as a rough estimate for Qwen tokenizer
    est_tokens = total_chars // 4
    avg_chars = total_chars / len(corpus) if corpus else 0

    print("\n=== Corpus stats ===")
    print(f"Total texts:        {len(corpus)}")
    print(f"Total characters:   {total_chars:,}")
    print(f"Average chars/text: {avg_chars:.0f}")
    print(f"Estimated tokens:   {est_tokens:,}  (rough, ~4 chars/token)")
    print(f"Shortest text:      {min(len(t) for t in corpus)} chars")
    print(f"Longest text:       {max(len(t) for t in corpus)} chars")
    texts_over_512_tok = sum(1 for t in corpus if len(t) > 512 * 4)
    print(f"Texts >512 tokens:  {texts_over_512_tok}  (rough estimate)")

    # --- Write output ---
    OUTPUT_PATH.write_text(json.dumps(corpus, indent=2, ensure_ascii=False), encoding="utf-8")
    print(f"\nWritten to: {OUTPUT_PATH}")


if __name__ == "__main__":
    main()
